document.addEventListener("click",t=>{t.target.getAttribute("data-action")==="reloadPage"&&window.location.reload()});const n=document.getElementById("stars");for(let t=0;t<80;t++){const a=document.createElement("div");a.className="star";const e=Math.random()*3+1;a.style.cssText=`width:${e}px;height:${e}px;left:${Math.random()*100}%;top:${Math.random()*100}%;--d:${2+Math.random()*4}s;animation-delay:${Math.random()*4}s;opacity:${Math.random()*.8}`,n.appendChild(a)}
